    17→open class BaseRepository {
    18→    var handler: ServerResponseHandler? = null
    19→
    20→    fun get188SharedPref(context: Context): Bet188SharePreferences {
    21→        return Bet188SharePreferences.getInstance(context)
    22→    }
    23→
    24→    fun setServerResponseHandler(handler: ServerResponseHandler) {
    25→        this.handler = handler
    26→    }
    27→
    28→    fun isLoginSuccess(context: Context): Boolean {
    29→        return Bet188SharePreferences.getInstance(context).isLoginSuccess
    30→    }
    31→
    32→    fun getVipTier(context: Context): Constants.UserVIPTier {
    33→        return Constants.UserVIPTier.fromInt(Bet188SharePreferences.getInstance(context).userVipTier)
    34→    }
    35→
    36→    fun isEnableAccessPrivilegeClub(context: Context): Boolean {
    37→        return Bet188SharePreferences.getInstance(context).isEnableAccessPrivilegeClub
    38→    }
    39→
    40→    fun isEnableReferAFriend(context: Context): Boolean {
    41→        return Bet188SharePreferences.getInstance(context).enableReferAFriend
    42→    }
    43→
    44→    fun isDisplayNewTnc(context: Context): Boolean {
    45→        return Bet188SharePreferences.getInstance(context).isDisplayNewTnC
    46→    }
    47→
    48→    fun getUserRegionCode(context: Context): String {
    49→        return Bet188SharePreferences.getInstance(context).userRegion
    50→    }
    51→
    52→    fun getAppLocaleLang(context: Context): String {
    53→        return Bet188SharePreferences.getInstance(context).appLocaleLanguage
    54→    }
    55→
    56→    fun getGeneralSettings(context: Context, entry: Constants.UpdateDeviceInfoEntry) {
    57→        val spi = SpiGetGeneralSettings()
    58→        spi.get(
    59→            context,
    60→            SpiGetGeneralSettings.Query(Bet188SharePreferences.getInstance(context).userRegion).toString(), null, object : SpiResponse<SpiGetGeneralSettings.Response>() {
    61→                override fun onResponse(resp: SpiGetGeneralSettings.Response?, status: Status, failCode: FailCode): Boolean {
    62→                    return if (status === Status.SUCCESS) {
    63→                        if (resp == null) return true
    64→                        if (valueOrGeneralError(resp.code) == ErrorCode.COMM0000) {
    65→                            Bet188SharePreferences.getInstance(context).adaChatbotLaunchKey = resp.body.chatbotKey
    66→                            Bet188SharePreferences.getInstance(context).setIsEnableAccountSecurityPage(resp.body.enableAccountSecurityPage)
    67→                            if (entry != Constants.UpdateDeviceInfoEntry.NONE && resp.body.fingerPrintKey.isNotEmpty()) {
    68→                                WebViewUtils.updateDeviceInfo(context, resp.body.fingerPrintKey, entry)
    69→                            }
    70→                        }
    71→                        true
    72→                    } else {
    73→                        true
    74→                    }
    75→                }
    76→
    77→            })
    78→    }
    79→}
    80→

