   183→    private fun AppCompatActivity.switchFragment(fragment: Fragment, tag: String? = null, isAnimation: Boolean, addToBackStack: Boolean) {
   184→        val ft = supportFragmentManager.beginTransaction()
   185→        if (isAnimation)
   186→            ft.setCustomAnimations(R.anim.slide_in_from_right, R.anim.slide_out_from_left, android.R.anim.slide_in_left, android.R.anim.slide_out_right)
   187→        ft.replace(getFragmentContainer(), fragment, tag)
   188→        if (addToBackStack) ft.addToBackStack(null).commit()
   189→        else ft.commit()
   190→    }
