   146→    private fun handleEffect(effect: LockPatternEffect) {
   147→        when (effect) {
   148→            is LockPatternEffect.ShowErrorPattern -> binding.viewLockPattern.errorPoint()
   149→
   150→            is LockPatternEffect.OpenBiometricPrompt -> {
   151→                fingerprintDialog = FingerprintDialogFragment()
   152→                fingerprintDialog?.show(childFragmentManager, FingerprintDialogFragment::class.simpleName)
   153→            }
   154→
   155→            is LockPatternEffect.AskEnableBioAuth -> {
   156→                if (fingerprintManager!!.isHardwareDetected && fingerprintManager!!.hasEnrolledFingerprints()) {
   157→                    if (!requireActivity().isFinishing) {
   158→                        DialogUtil.showTwoButtonDialogFragment(
   159→                            requireContext(),
   160→                            this,
   161→                            StringsRepository.getString(UiStr.FINGERPRINTENABLETITLE),
   162→                            StringsRepository.getString(UiStr.FINGERPRINTENABLEMESSAGE),
   163→                            StringsRepository.getString(UiStr.TXTBTNCOMYES),
   164→                            StringsRepository.getString(UiStr.TXTBTNCOMNO),
   165→                            BIO_AUTH_SETTING
   166→                        )
   167→                    }
   168→                }
   169→                else {
   170→                    vm.saveKey()
   171→                }
   172→            }
   173→
   174→            is LockPatternEffect.Finish -> {
   175→                val intent = Intent().apply {
   176→                    effect.savedKey?.let { putExtra(RESULT_DATA_SAVE_KEY, it) }
   177→                }
   178→                requireActivity().setResult(if (effect.ok) RESULT_OK else Activity.RESULT_CANCELED, intent)
   179→                requireActivity().finish()
   180→            }
   181→
   182→            is LockPatternEffect.Logout -> {
   183→                sharedPreferences.isNeedSettingLockPattern = true
   184→                sharedPreferences.lockPatternKey = ""
   185→                CommonUtils.handleUserLogout(requireContext())
   186→                requireActivity().finish()
