package com.xuenn.bet188.revamp.viewmodel

import android.os.Parcelable
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.xuenn.bet188.revamp.model.data.LockPatternUiState
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import kotlinx.parcelize.Parcelize

const val LOCK_PATTERN_FUNCTION_KEY: String = "LOCK_PATTERN_FUNCTION_KEY"
const val LOCK_PATTERN_PASSWORD_KEY: String = "LOCK_PATTERN_PASSWORD_KEY"
const val RESULT_DATA_SAVE_KEY: String = "RESULT_DATA_SAVE_KEY"

@Parcelize
enum class LockPatternFunction: Parcelable { SET_KEY, UNLOCK }
enum class LockPatternState { KEY_SETTING, KEY_SETTING_DONE, KEY_SETTING_CONFIRM, KEY_SETTING_CONFIRM_DONE, UNLOCK }



sealed interface LockPatternEffect {
    data object ShowErrorPattern : LockPatternEffect
    data object OpenBiometricPrompt : LockPatternEffect
    data object AskEnableBioAuth : LockPatternEffect
    data object Logout : LockPatternEffect
    data class Finish(val ok: Boolean, val savedKey: String? = null) : LockPatternEffect

}

class LockPatternViewModel(private val savedState: SavedStateHandle): ViewModel() {

    private val _state = MutableStateFlow(
        LockPatternUiState(
            function = savedState.get<LockPatternFunction>(LOCK_PATTERN_FUNCTION_KEY) ?: LockPatternFunction.SET_KEY,
            lockKeyForUnlock = savedState.get<String>(LOCK_PATTERN_PASSWORD_KEY) ?: "1234",
            state = if ((savedState.get<LockPatternFunction>(LOCK_PATTERN_FUNCTION_KEY)
                    ?: LockPatternFunction.SET_KEY) == LockPatternFunction.UNLOCK
            ) LockPatternState.UNLOCK else LockPatternState.KEY_SETTING
        )
    )
    val state: StateFlow<LockPatternUiState> = _state.asStateFlow()

    private val _effects = MutableSharedFlow<LockPatternEffect>()
    val effects: SharedFlow<LockPatternEffect> = _effects.asSharedFlow()

    private fun emitError() = viewModelScope.launch { _effects.emit(LockPatternEffect.ShowErrorPattern) }

    private fun update(newState: LockPatternUiState) {
        _state.value = newState
    }

    fun onBioContext(
        biometricAvailable: Boolean,
        lockPatternEnabled: Boolean,
        enableBioAuth: Boolean,
        setBioAuth: Boolean
    ) {
        if (!lockPatternEnabled) return
        if (!biometricAvailable) return

        viewModelScope.launch {
            when {
                enableBioAuth -> _effects.emit(LockPatternEffect.OpenBiometricPrompt)
                !setBioAuth -> _effects.emit(LockPatternEffect.AskEnableBioAuth)
            }
        }
    }


    fun onPatternChanged(pass: String?) {
        val s = _state.value
        if (pass == null) {
            when (s.state) {
                LockPatternState.KEY_SETTING ->
                    update(s.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
                LockPatternState.KEY_SETTING_DONE ->
                    update(s.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
                LockPatternState.KEY_SETTING_CONFIRM, LockPatternState.KEY_SETTING_CONFIRM_DONE ->
                    update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
                LockPatternState.UNLOCK -> { /* no-op */ }
            }
            return
        }

        when (s.state) {
            LockPatternState.KEY_SETTING -> {
                update(
                    s.copy(
                        lockKeyForSave = pass,
                        state = LockPatternState.KEY_SETTING_DONE,
                        canConfirm = true,
                        showConfirm = true
                    )
                )
            }
            LockPatternState.KEY_SETTING_CONFIRM -> {
                if (s.lockKeyForSave == pass) {
                    update(
                        s.copy(
                            state = LockPatternState.KEY_SETTING_CONFIRM_DONE,
                            canConfirm = true, showConfirm = true
                        )
                    )
                } else {
                    emitError()
                }
            }
            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
                if (s.lockKeyForSave == pass) {
                } else {
                    emitError()
                    update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
                }
            }
            LockPatternState.UNLOCK -> {
                if (s.lockKeyForUnlock == pass) {
                    viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = true)) }
                } else {
                    val cnt = s.unlockErrorCount + 1
                    emitError()
                    if (cnt >= 5) {
                        viewModelScope.launch { _effects.emit(LockPatternEffect.Logout) }
                    }
                    update(s.copy(unlockErrorCount = cnt))
                }
            }
            else -> {}
        }
    }

    fun onClickCancel() {
        val s = _state.value
        when (s.state) {
            LockPatternState.KEY_SETTING -> {
                viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = false)) }
            }
            LockPatternState.KEY_SETTING_DONE,
            LockPatternState.KEY_SETTING_CONFIRM -> {
                update(
                    s.copy(
                        state = LockPatternState.KEY_SETTING,
                        canConfirm = false,
                        showConfirm = false
                    )
                )
            }
            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
                update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
            }
            LockPatternState.UNLOCK -> {
            }
        }
    }

    fun onClickConfirm() {
        val s = _state.value
        when (s.state) {
            LockPatternState.KEY_SETTING_DONE -> {
                update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
            }
            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
                viewModelScope.launch { _effects.emit(LockPatternEffect.AskEnableBioAuth) }
            }
            else -> Unit
        }
    }

    fun saveKey() {
        viewModelScope.launch {
            _effects.emit(LockPatternEffect.Finish(ok = true, savedKey = _state.value.lockKeyForSave))
        }
    }

    fun onDecideEnableBioAuth() {
        viewModelScope.launch {
            _effects.emit(LockPatternEffect.Finish(ok = true, savedKey = _state.value.lockKeyForSave))
        }
    }

    fun onBiometricSucceededFromDialog() {
        viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = true)) }
    }

    fun goToKeySetting() {
        update(_state.value.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
    }

}

