package com.xuenn.bet188.revamp.view.lockpattern

import android.annotation.SuppressLint
import android.app.Activity
import android.content.Intent
import android.os.Bundle
import android.view.View
import androidx.appcompat.app.AppCompatActivity.RESULT_OK
import androidx.core.hardware.fingerprint.FingerprintManagerCompat
import androidx.fragment.app.viewModels
import androidx.lifecycle.lifecycleScope
import androidx.lifecycle.repeatOnLifecycle
import com.xuenn.bet188.R
import com.xuenn.bet188.comm.dialog.DialogUtil
import com.xuenn.bet188.comm.dialog.iface.ISimpleDialogListener
import com.xuenn.bet188.databinding.FragmentLockPatternBinding
import com.xuenn.bet188.revamp.model.data.LockPatternUiState
import com.xuenn.bet188.revamp.utils.CommonUtils
import com.xuenn.bet188.revamp.model.data.UiStr
import com.xuenn.bet188.revamp.model.data.repo.StringsRepository
import com.xuenn.bet188.revamp.utils.fingerprint.FingerprintDialogFragment
import com.xuenn.bet188.revamp.view.base.BaseBindingFragment
import com.xuenn.bet188.revamp.viewmodel.LockPatternEffect
import com.xuenn.bet188.revamp.viewmodel.LockPatternState
import com.xuenn.bet188.revamp.viewmodel.LockPatternViewModel
import com.xuenn.bet188.revamp.viewmodel.RESULT_DATA_SAVE_KEY
import com.xuenn.bet188.revamp.widget.LockPatternView
import kotlinx.coroutines.launch


@SuppressLint("RestrictedApi")
class LockPatternFragment: BaseBindingFragment<FragmentLockPatternBinding>(),
    LockPatternView.OnPatterChangeListener, FingerprintDialogFragment.FingerprintDialogCallback, ISimpleDialogListener {

    private var fingerprintDialog: FingerprintDialogFragment? = null
    private var fingerprintManager: FingerprintManagerCompat? = null

    private val BIO_AUTH_SETTING: Int = 1

    private val vm: LockPatternViewModel by viewModels()

    companion object {
        fun newInstance(bundle: Bundle): LockPatternFragment {
            val fragment = LockPatternFragment()
            fragment.arguments = bundle
            return fragment
        }
    }

    override fun onResume() {
        super.onResume()
        fingerprintManager = FingerprintManagerCompat.from(requireContext())

        vm.onBioContext(
            biometricAvailable = fingerprintManager!!.isHardwareDetected && fingerprintManager!!.hasEnrolledFingerprints(),
            lockPatternEnabled = sharedPreferences.isLockPatternEnable,
            enableBioAuth = sharedPreferences.enableBioAuth,
            setBioAuth = sharedPreferences.setBioAuth
        )
    }

    override fun onPause() {
        super.onPause()
        fingerprintDialog?.dismissAllowingStateLoss()
        fingerprintDialog = null
    }

    override fun initView() {
        binding.viewLockPattern.setPatterChangeListener(this)
        viewLifecycleOwner.lifecycleScope.launch {
            viewLifecycleOwner.repeatOnLifecycle(androidx.lifecycle.Lifecycle.State.STARTED) {
                launch {
                    vm.state.collect { state -> render(state) }
                }
                launch {
                    vm.effects.collect { eff -> handleEffect(eff) }
                }
            }
        }
    }

    override fun initData() {
    }

    override fun getLayoutId() = R.layout.fragment_lock_pattern

    override fun onPatterChange(passString: String?) {
        vm.onPatternChanged(passString)
    }

    override fun onPatterStart(isStart: Boolean) {
    }

    override fun onAuthenticationSucceeded() {
        vm.onBiometricSucceededFromDialog()
    }


    private fun render(uiState: LockPatternUiState) {
        binding.textViewLockPatternMessage.text = when (uiState.state) {
            LockPatternState.KEY_SETTING -> StringsRepository.getString(UiStr.TXTDRAWLOCKPATTERN)
            LockPatternState.KEY_SETTING_DONE -> StringsRepository.getString(UiStr.TXTPATTERNNEXTCONTINUE)
            LockPatternState.KEY_SETTING_CONFIRM -> StringsRepository.getString(UiStr.TXTDRAWAGAIN)
            LockPatternState.KEY_SETTING_CONFIRM_DONE -> StringsRepository.getString(UiStr.TXTDRAWAGAIN)
            LockPatternState.UNLOCK -> StringsRepository.getString(UiStr.TXTDRAWUNLOCKSCREEN)
        }

        binding.viewLockPattern.isEnabled = when (uiState.state) {
            LockPatternState.KEY_SETTING_DONE,
            LockPatternState.KEY_SETTING_CONFIRM_DONE -> false
            else -> true
        }

        when(uiState.state) {
            LockPatternState.KEY_SETTING_CONFIRM,
            LockPatternState.KEY_SETTING -> binding.viewLockPattern.resets()
            else -> {}
        }

        binding.buttonLockPatternCancel.apply {
            visibility = if (uiState.state == LockPatternState.UNLOCK) View.INVISIBLE else View.VISIBLE
            text = when (uiState.state) {
                LockPatternState.KEY_SETTING,
                LockPatternState.KEY_SETTING_CONFIRM -> StringsRepository.getString(UiStr.TXTBTNCOMCANCEL)
                LockPatternState.KEY_SETTING_DONE,
                LockPatternState.KEY_SETTING_CONFIRM_DONE -> StringsRepository.getString(UiStr.TXTREDRAW)
                LockPatternState.UNLOCK -> StringsRepository.getString(UiStr.TXTBTNCOMCANCEL)
            }
            setOnClickListener { vm.onClickCancel() }
        }

        binding.buttonLockPatternConfirm.apply {
            visibility = if (uiState.showConfirm) View.VISIBLE else View.INVISIBLE
            isEnabled = uiState.canConfirm
            text = when (uiState.state) {
                LockPatternState.KEY_SETTING,
                LockPatternState.KEY_SETTING_DONE -> StringsRepository.getString(UiStr.LOBBYMESSAGENEXT)
                LockPatternState.KEY_SETTING_CONFIRM,
                LockPatternState.KEY_SETTING_CONFIRM_DONE -> StringsRepository.getString(UiStr.TXTDONE)
                LockPatternState.UNLOCK -> StringsRepository.getString(UiStr.TXTUNLOCK)
            }
            setOnClickListener { vm.onClickConfirm() }
        }
    }

    private fun handleEffect(effect: LockPatternEffect) {
        when (effect) {
            is LockPatternEffect.ShowErrorPattern -> binding.viewLockPattern.errorPoint()

            is LockPatternEffect.OpenBiometricPrompt -> {
                fingerprintDialog = FingerprintDialogFragment()
                fingerprintDialog?.show(childFragmentManager, FingerprintDialogFragment::class.simpleName)
            }

            is LockPatternEffect.AskEnableBioAuth -> {
                if (fingerprintManager!!.isHardwareDetected && fingerprintManager!!.hasEnrolledFingerprints()) {
                    if (!requireActivity().isFinishing) {
                        DialogUtil.showTwoButtonDialogFragment(
                            requireContext(),
                            this,
                            StringsRepository.getString(UiStr.FINGERPRINTENABLETITLE),
                            StringsRepository.getString(UiStr.FINGERPRINTENABLEMESSAGE),
                            StringsRepository.getString(UiStr.TXTBTNCOMYES),
                            StringsRepository.getString(UiStr.TXTBTNCOMNO),
                            BIO_AUTH_SETTING
                        )
                    }
                }
                else {
                    vm.saveKey()
                }
            }

            is LockPatternEffect.Finish -> {
                val intent = Intent().apply {
                    effect.savedKey?.let { putExtra(RESULT_DATA_SAVE_KEY, it) }
                }
                requireActivity().setResult(if (effect.ok) RESULT_OK else Activity.RESULT_CANCELED, intent)
                requireActivity().finish()
            }

            is LockPatternEffect.Logout -> {
                sharedPreferences.isNeedSettingLockPattern = true
                sharedPreferences.lockPatternKey = ""
                CommonUtils.handleUserLogout(requireContext())
                requireActivity().finish()
            }
        }
    }

    override fun onPositiveButtonClicked(requestCode: Int) {
        if (requestCode == BIO_AUTH_SETTING) {
            sharedPreferences.enableBioAuth = true
            sharedPreferences.setBioAuth = true
            vm.onDecideEnableBioAuth()
        }
    }

    override fun onNegativeButtonClicked(requestCode: Int) {
        if (requestCode == BIO_AUTH_SETTING) {
            sharedPreferences.enableBioAuth = false
            sharedPreferences.setBioAuth = true
            vm.onDecideEnableBioAuth()
        }
    }
}

