package com.xuenn.bet188.revamp.widget

import android.content.Context
import android.view.View
import android.widget.PopupWindow
import android.widget.RelativeLayout
import androidx.lifecycle.MutableLiveData
import androidx.recyclerview.widget.LinearLayoutManager
import com.xuenn.bet188.databinding.ViewPopupChooserBinding
import com.xuenn.bet188.revamp.adapter.PopupChooserAdapter
import com.xuenn.bet188.revamp.model.data.ChooserItem


class ListPopupWindow<T>(context: Context, binding: ViewPopupChooserBinding) : PopupWindow() {
    private var context: Context
    private var binding: ViewPopupChooserBinding

    init {
        this.context = context
        this.binding = binding

        contentView = binding.root
        width = RelativeLayout.LayoutParams.WRAP_CONTENT
        height = RelativeLayout.LayoutParams.WRAP_CONTENT
        isFocusable = true
    }

    fun setChooserAdapter(dataList: List<ChooserItem<T>>, liveData: MutableLiveData<T>) {
        val adapter = PopupChooserAdapter<T>(context)
        adapter.setOnItemClickListener(object : PopupChooserAdapter.OnItemClick<T> {
            override fun onClick(data: ChooserItem<T>) {
                liveData.value = data.oriData
                this@ListPopupWindow.dismiss()
            }
        })
        binding.recyclerView.layoutManager = LinearLayoutManager(context)
        binding.recyclerView.adapter = adapter //must be last

        //set data
        adapter.setDataList(dataList)
    }

    fun show(anchorView: View, xOffset: Int = 0, yOffset: Int = 0) {
        showAsDropDown(anchorView, xOffset, yOffset)
    }
}

