                                    if (isEnableFacebookOAuth.value != null) isEnableFacebookOAuth.value = RegionUtil.getRegion(appContext, resp.body.preference!!.region, null).isAllowFacebookOAuth
                                }

                                else -> {
                                    val regionList = repo.getRegionList(appContext)
                                    if (regionList.isNotEmpty()) {
                                        selectedRegion.value = regionList[0]
                                        performGetAgeCurrencyListOfRegion()
