            callback = object : SpiResponse<SpiSubmitRegistration.Response>() {
                override fun onResponse(
                    resp: SpiSubmitRegistration.Response?, status: Status, failCode: FailCode
                ): Boolean {
                    _state.update { it.copy(isLoading = false) }
                    return if (status === Status.SUCCESS) {
                        when (valueOrGeneralError(resp!!.code)) {
                            ErrorCode.COMM0000 -> {
                                val returnStatus = RegisterRepository.Companion.RegisterReturnStatus.fromCode(resp.body.returnCode)
                                viewModelScope.launch {
                                    when (returnStatus) {
                                        RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS -> {
                                            if (oAuthUserData.oAuthType == Constants.OAuthType.Unknown) {
                                                performLogin(userName, pwd)
                                            } else {
                                                performOAuthLoginAfterRegister(oAuthUserData)
                                            }
                                        }
                                        RegisterRepository.Companion.RegisterReturnStatus.USERNAME_EXIST ->
                                            _effects.emit(RegisterEffect.ShowUsernameExistsError)
                                        RegisterRepository.Companion.RegisterReturnStatus.EMAIL_EXIST ->
                                            _effects.emit(RegisterEffect.ShowEmailExistsError)
                                        RegisterRepository.Companion.RegisterReturnStatus.EMAIL_USERNAME_EXIST ->
                                            _effects.emit(RegisterEffect.ShowEmailAndUsernameExistError)
                                        RegisterRepository.Companion.RegisterReturnStatus.FAIL ->
                                            _effects.emit(RegisterEffect.ShowRegisterFail)
                                        RegisterRepository.Companion.RegisterReturnStatus.USERNAME_SAME_AS_PASSWORD ->
                                            _effects.emit(RegisterEffect.ShowUsernamePasswordSameError)
                                        RegisterRepository.Companion.RegisterReturnStatus.OAUTH_FAIL ->
                                            _effects.emit(RegisterEffect.ShowOAuthFail)
                                        RegisterRepository.Companion.RegisterReturnStatus.OAUTH_ID_EXIST ->
                                            _effects.emit(RegisterEffect.ShowOAuthIdExists)
                                        else -> {}
                                    }
                                }
                                returnStatus == RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS
                            }

                            else -> false
                        }
                    } else {
                        false
                    }
                }
            })
    }

    fun performLogin(userName: String, pwd: String) {
        _state.update { it.copy(isLoading = true) }
        repo.login(appContext, userName, pwd, object : SpiResponse<SpiLogin.Response>() {
            override fun onResponse(
                resp: SpiLogin.Response?, status: Status, failCode: FailCode
            ): Boolean {
