                            repo.saveLoginSuccessInfo(appContext, resp.body)
                            viewModelScope.launch { _effects.emit(RegisterEffect.OpenLockPatternSetting) }
                            repo.getGeneralSettings(appContext, Constants.UpdateDeviceInfoEntry.REGISTER)
                            true
                        }

                        else -> {
                            viewModelScope.launch { _effects.emit(RegisterEffect.ShowLoginFailed) }
                            true
                        }
                    }
                } else {
                    return false
                }
            }
        })
    }

    private fun performOAuthLoginAfterRegister(oAuthUserData: OAuthUserData) {
        _state.update { it.copy(isLoading = true) }
        repo.oAuthLogin(
            appContext, oAuthUserData = oAuthUserData,
            callback = object : SpiResponse<SpiLogin.Response>() {
                override fun onResponse(
                    resp: SpiLogin.Response?, status: Status, failCode: FailCode
                ): Boolean {
                    _state.update { it.copy(isLoading = false) }
                    if (status === Status.SUCCESS) {
                        return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
                            ErrorCode.COMM0000 -> {
                                repo.saveLoginSuccessInfo(appContext, resp.body)
                                viewModelScope.launch { _effects.emit(RegisterEffect.OpenLockPatternSetting) }
                                repo.getGeneralSettings(appContext, Constants.UpdateDeviceInfoEntry.REGISTER)
                                true
                            }

                            else -> {
                                viewModelScope.launch { _effects.emit(RegisterEffect.ShowLoginFailed) }
                                true
                            }
                        }
                    } else {
                        return false
                    }
                }
            })
    }
}

