package com.xuenn.bet188.revamp.utils.oauth

import android.app.Activity
import com.xuenn.bet188.revamp.callback.IGoogleOAuthGetListener

object GoogleOAuthHelper : BaseOAuthHelper() {
    suspend fun launchSignIn(
        activity: Activity,
        launchMillis: Long,
        listener: IGoogleOAuthGetListener?
    ) {
        val ok = tryAcquire(
            activity = activity,
            launchMillis = launchMillis,
            onReachLimit = { listener?.reachOAuthLimit(activity) }
        )
        if (!ok) return

        GoogleOAuthUtil(activity).launchGoogleSignIn(listener)
    }
}

