package com.xuenn.bet188.revamp.utils.oauth

import android.app.Activity
import androidx.credentials.CredentialManager
import androidx.credentials.CustomCredential
import androidx.credentials.GetCredentialRequest
import androidx.credentials.GetCredentialResponse
import androidx.credentials.exceptions.GetCredentialCancellationException
import com.google.android.libraries.identity.googleid.GetSignInWithGoogleOption
import com.google.android.libraries.identity.googleid.GoogleIdTokenCredential
import com.google.android.libraries.identity.googleid.GoogleIdTokenParsingException
import com.xuenn.bet188.revamp.callback.IGoogleOAuthGetListener
import com.xuenn.bet188.revamp.utils.AndroidUtils
import org.json.JSONObject

/**
 * @param context used to launch any UI needed; use an activity context to make sure the UI will be launched within the same task stack
 **/

class GoogleOAuthUtil(val context: Activity) {
    private var WEB_CLIENT_ID: String = ""
    private var credentialManager: CredentialManager = CredentialManager.create(context)

    init {
        WEB_CLIENT_ID = AndroidUtils.getMetaDataString(context, "GoogleOAuthWebClientId")
    }

    companion object {
        const val TAG = "GAuth"
        private const val KEY_ID_SUB = "sub"
        private const val KEY_EMAIL_VERIFIED = "email_verified"

        private fun decodeIdToken(idToken: String): JSONObject? {
            return try {
                val parts = idToken.split(".")
                if (parts.size != 3) return null

                val decodedBytes = android.util.Base64.decode(parts[1], android.util.Base64.NO_WRAP)
                val jsonString = String(decodedBytes, Charsets.UTF_8)

                JSONObject(jsonString)
            } catch (e: Exception) {
                e.printStackTrace()
                null
            }
        }

        fun getOAuthIdForSPI(idToken: String): String {
            val tokenObject = decodeIdToken(idToken)
            return if (tokenObject != null) {
                tokenObject.getString(KEY_ID_SUB)
            } else {
                ""
            }
        }

        fun isEmailVerified(idToken: String): Boolean {
            val tokenObject = decodeIdToken(idToken)
            return tokenObject?.getBoolean(KEY_EMAIL_VERIFIED) ?: false
        }
    }

    suspend fun launchGoogleSignIn(listener: IGoogleOAuthGetListener?) {
        listener?.setProgressStatus(true)
        try {
            val signInWithGoogleOption: GetSignInWithGoogleOption = GetSignInWithGoogleOption.Builder(WEB_CLIENT_ID)
                .build()

            val request: GetCredentialRequest = GetCredentialRequest.Builder()
                .addCredentialOption(signInWithGoogleOption)
                .build()

            val result = credentialManager.getCredential(context, request)

            listener?.setProgressStatus(false)
//            GoogleOAuthHelper.setRecord(context, Pair(0, 0L))  //reset info
            handleGetCredentialResult(result, listener)
        } catch (e: Exception) {
            listener?.setProgressStatus(false)
            if (e !is GetCredentialCancellationException)
                listener?.launchFail(e)
        }
    }

    private fun handleGetCredentialResult(result: GetCredentialResponse, listener: IGoogleOAuthGetListener?) {
        when (val credential = result.credential) {
